import { useState } from "react";
import enrollmentService from "../services/enrollmentService";

const EnrollmentsPage = () => {
  const [form, setForm] = useState({ studentId: "", courseId: "" });
  const [message, setMessage] = useState("");
  const [error, setError] = useState("");

  const handleSubmit = async (event) => {
    event.preventDefault();
    setMessage("");
    setError("");

    try {
      const response = await enrollmentService.enroll({
        studentId: Number(form.studentId),
        courseId: Number(form.courseId)
      });
      if (response.success) {
        setMessage(response.message);
        setForm({ studentId: "", courseId: "" });
        return;
      }
      setError(response.message || "Failed to enroll student.");
    } catch (err) {
      setError(err.message || "Failed to enroll student.");
    }
  };

  return (
    <section>
      <div className="page-header">
        <h2>Enrollments</h2>
        <p className="muted">Enroll students into courses.</p>
      </div>

      <div className="card">
        <h3>Enroll student</h3>
        <form onSubmit={handleSubmit} className="form-grid">
          <div className="form-group">
            <label>Student Id</label>
            <input
              name="studentId"
              type="number"
              value={form.studentId}
              onChange={(event) =>
                setForm((prev) => ({
                  ...prev,
                  studentId: event.target.value
                }))
              }
              required
            />
          </div>
          <div className="form-group">
            <label>Course Id</label>
            <input
              name="courseId"
              type="number"
              value={form.courseId}
              onChange={(event) =>
                setForm((prev) => ({ ...prev, courseId: event.target.value }))
              }
              required
            />
          </div>
          <div className="actions">
            <button className="btn btn-primary" type="submit">
              Enroll
            </button>
          </div>
        </form>
      </div>

      {message && <div className="alert alert-success">{message}</div>}
      {error && <div className="alert alert-error">{error}</div>}
    </section>
  );
};

export default EnrollmentsPage;
